void rearrangeArray(vector<int>& arr, int n) {
    vector<int> result(n);

    int posIndex = 0;  // even indices
    int negIndex = 1;  // odd indices

    for (int i = 0; i < n; i++) {
        if (arr[i] >= 0) {
            result[posIndex] = arr[i];
            posIndex += 2;
        } else {
            result[negIndex] = arr[i];
            negIndex += 2;
        }
    }

    arr = result;
}

