void rearrangeArray(int arr[], int n) {
    int *result = (int *)malloc(n * sizeof(int));

    int posIndex = 0;  // even index
    int negIndex = 1;  // odd index

    for (int i = 0; i < n; i++) {
        if (arr[i] >= 0) {
            result[posIndex] = arr[i];
            posIndex += 2;
        } else {
            result[negIndex] = arr[i];
            negIndex += 2;
        }
    }

    // Copy back to original array
    for (int i = 0; i < n; i++) {
        arr[i] = result[i];
    }

    free(result);
}

code.Java:
public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    int n = sc.nextInt();
    int[] nums = new int[n];
    for(int i = 0; i < n; i++) {
        nums[i] = sc.nextInt();
    }

    List<Integer> pos = new ArrayList<>();
    List<Integer> neg = new ArrayList<>();

    for(int x : nums) {
        if(x > 0) pos.add(x);
        else neg.add(x);
    }

    StringBuilder sb = new StringBuilder();
    for(int i = 0; i < n/2; i++) {
        sb.append(pos.get(i)).append(" ").append(neg.get(i)).append(" ");
    }

    System.out.println(sb.toString().trim());
}

code.JavaScript:
function rearrangeArray(arr, n) {
    let pos = [];
    let neg = [];

    // Separate positives and negatives
    for (let x of arr) {
        if (x > 0) pos.push(x);
        else neg.push(x);
    }

    // Print in alternating order
    let result = [];
    for (let i = 0; i < n / 2; i++) {
        result.push(pos[i]);
        result.push(neg[i]);
    }
    console.log(result.join(" "));
}
